mapper.select:
SELECT c.contact_id, c.customer_id, cu.company_name AS customer_name, c.name, c.position, c.phone, c.email, c.wechat, c.is_primary, c.last_contact_time, c.notes, c.create_time FROM crm_contact c LEFT JOIN crm_customer cu ON c.customer_id = cu.customer_id WHERE c.status = 1
AND c.customer_id = #{query.customerId}
AND c.name LIKE CONCAT('%', #{query.keyword}, '%')
AND c.is_primary = #{query.isPrimary}
ORDER BY c.is_primary DESC, c.create_time DESC
